Pour développer un logiciel qui ferme toutes les applications en cours d'exécution sur un bureau Windows, vous pouvez utiliser le langage de programmation C# avec la bibliothèque Windows API. Voici un exemple de code pour fermer toutes les applications en cours d'exécution :

```csharp
using System;
using System.Diagnostics;
using System.Runtime.InteropServices;

class Program
{
    [DllImport("user32.dll")]
    private static extern IntPtr FindWindow(string lpClassName, string lpWindowName);

    [DllImport("user32.dll")]
    private static extern bool EnumWindows(EnumWindowsProc enumProc, IntPtr lParam);

    [DllImport("user32.dll")]
    private static extern bool EnumChildWindows(IntPtr hWndParent, EnumWindowsProc enumProc, IntPtr lParam);

    [DllImport("user32.dll")]
    private static extern bool PostMessage(IntPtr hWnd, uint Msg, IntPtr wParam, IntPtr lParam);

    private const uint WM_CLOSE = 0x0010;

    private delegate bool EnumWindowsProc(IntPtr hWnd, IntPtr lParam);

    static void Main(string[] args)
    {
        EnumWindows(new EnumWindowsProc(EnumWindows), IntPtr.Zero);
    }

    private static bool EnumWindows(IntPtr hWnd, IntPtr lParam)
    {
        if (hWnd == IntPtr.Zero)
            return true;

        if (IsWindowVisible(hWnd))
        {
            PostMessage(hWnd, WM_CLOSE, IntPtr.Zero, IntPtr.Zero);
        }

        return true;
    }

    private static bool IsWindowVisible(IntPtr hWnd)
    {
        return GetWindowLong(hWnd, -16) & 0x80000000 != 0;
    }
}
```

Ce code utilise la bibliothèque Windows API pour parcourir toutes les fenêtres en cours d'exécution et fermer les applications en utilisant la méthode `PostMessage` avec le message `WM_CLOSE`.
